CREATE TABLE delivery_requests (request_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), order_id UUID NOT NULL, order_created_at TIMESTAMPTZ NOT NULL, partner_id UUID REFERENCES users(user_id), strategy VARCHAR(32) NOT NULL DEFAULT 'nearest', status VARCHAR(30) NOT NULL DEFAULT 'pending_acceptance', created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), FOREIGN KEY(order_id,order_created_at) REFERENCES orders(order_id,created_at));
CREATE TABLE deliveries (delivery_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), order_id UUID NOT NULL, order_created_at TIMESTAMPTZ NOT NULL, partner_id UUID NOT NULL REFERENCES users(user_id), status delivery_status NOT NULL DEFAULT 'assigned', assigned_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE(order_id,order_created_at), FOREIGN KEY(order_id,order_created_at) REFERENCES orders(order_id,created_at));
CREATE TABLE delivery_status_history (history_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), delivery_id UUID NOT NULL REFERENCES deliveries(delivery_id) ON DELETE CASCADE, from_status delivery_status, to_status delivery_status NOT NULL, changed_by UUID REFERENCES users(user_id), changed_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
